const RECIPES = [];

/* Helper to register a recipe with an auto id and sensible defaults. */
function addRecipe(o) {
  if (!o.id) o.id = "r" + (RECIPES.length + 1);
  o.ingredients = o.ingredients || [];
  o.steps = o.steps || [];
  o.tips = o.tips || [];
  o.nutrition = o.nutrition || { protein: "-", carbs: "-", fat: "-", fiber: "-" };
  RECIPES.push(o);
  return o;
}

