/* Map legacy fields to the unified RECIPES schema, preserving any data that
   is already provided (description, ingredients, instructions, calories,
   nutrition, tips) instead of overwriting it with placeholders. */
const legacyMap = {
  prep: r => r.prepTime,
  cook: r => r.cookTime,
  calories: r => (typeof r.calories === 'number' ? r.calories : 500),
  steps: r => (Array.isArray(r.instructions) && r.instructions.length ? r.instructions : []),
  tips: r => (Array.isArray(r.tips) ? r.tips : []),
  nutrition: r => (r.nutrition && typeof r.nutrition === 'object' ? r.nutrition : { protein: "-", carbs: "-", fat: "-", fiber: "-" })
};

recipes.forEach(r => {
  const mapped = { ...r };
  Object.keys(legacyMap).forEach(k => { mapped[k] = legacyMap[k](r); });
  if (!mapped.id) mapped.id = "r" + (RECIPES.length + 1);
  mapped.ingredients = mapped.ingredients || [];
  mapped.steps = mapped.steps || [];
  mapped.tips = mapped.tips || [];
  mapped.nutrition = mapped.nutrition || { protein: "-", carbs: "-", fat: "-", fiber: "-" };
  RECIPES.push(mapped);
});
